
.header {
  border-bottom: 1px solid var(--c-border);
  padding: 10px 12px;
}

.header-row {
  display: flex;
  align-items: center;
  gap: 10px;
  flex-wrap: wrap;
}

.label {
  font-size: 0.75rem;
  color: var(--c-text-muted);
  white-space: nowrap;
}

.energy-section {
  display: flex;
  align-items: center;
  gap: 6px;
  flex: 1;
  min-width: 160px;
}

.energy-track {
  flex: 1;
  height: 14px;
  background: var(--c-surface-light);
  border: 1px solid var(--c-border);
  overflow: hidden;
  position: relative;
}

.energy-fill {
  position: absolute;
  left: 0;
  top: 0;
  bottom: 0;
  transition: width 0.3s ease, background 0.3s ease;
}

.value {
  font-size: 0.8rem;
  font-weight: bold;
  min-width: 28px;
  text-align: right;
  font-variant-numeric: tabular-nums;
}

.evolution-badge {
  padding: 3px 10px;
  font-size: 0.78rem;
  font-weight: bold;
  color: #0f172a;
  border-radius: 4px;
  white-space: nowrap;
}

.ling-she-count {
  display: flex;
  align-items: baseline;
  gap: 1px;
  padding: 3px 8px;
  border: 1px solid var(--c-border);
  border-radius: 4px;
  font-size: 0.8rem;
}

.ling-she-count.capped {
  border-color: var(--c-gold);
  color: var(--c-gold);
}

.count-num {
  font-weight: bold;
  font-variant-numeric: tabular-nums;
}

.count-max {
  color: var(--c-text-muted);
  font-size: 0.7rem;
}
