
.mini-bar {
  display: flex;
  justify-content: center;
  gap: 16px;
  padding: 6px 12px;
  border-top: 1px solid var(--c-border);
  background: var(--c-surface);
  font-size: 0.75rem;
}

.mini-item {
  display: flex;
  align-items: center;
  gap: 4px;
  color: var(--c-text-muted);
}

.mini-dot {
  width: 6px;
  height: 6px;
  border-radius: 50%;
  display: inline-block;
}
