
.card {
  width: 100%;
  max-width: 540px;
  background-color: var(--c-bg);
  border: 1px solid var(--c-border);
  display: flex;
  flex-direction: column;
  font-family: var(--font-stack);
  color: var(--c-text);
  font-size: 13px;
  line-height: 1.35;
  margin: 0 auto;
}

.content-area {
  min-height: 0;
}

.tab-pane {
  display: none;
  animation: fadeEffect 0.3s;
}

.tab-pane.active {
  display: block;
}

@keyframes fadeEffect {
  from {
    opacity: 0;
    transform: translateY(4px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}
