
.slave-panel {
  padding: 12px;
}

.empty-state {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  padding: 24px;
  color: var(--c-text-muted);
  font-size: 0.9rem;
}

.empty-icon {
  font-size: 1.2rem;
}

.slave-header {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 10px;
  flex-wrap: wrap;
}

.slave-name {
  font-size: 1.05rem;
  font-weight: bold;
}

.slave-badge {
  padding: 2px 8px;
  border-radius: 4px;
  font-size: 0.7rem;
  font-weight: bold;
  color: #fff;
}

.slave-badge.rating {
  background: var(--c-surface-light);
  border: 1px solid var(--c-border-light);
}

.body-card {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 6px;
  margin-bottom: 8px;
  padding: 8px;
  background: var(--c-surface);
  border: 1px solid var(--c-border);
  border-radius: 6px;
}

.body-stat {
  display: flex;
  flex-direction: column;
  gap: 1px;
}

.body-label {
  font-size: 0.65rem;
  color: var(--c-text-muted);
  text-transform: uppercase;
}

.body-val {
  font-size: 0.85rem;
  font-weight: 600;
}

.tags-row {
  display: flex;
  flex-wrap: wrap;
  gap: 4px;
  margin-bottom: 6px;
}

.tag-pill {
  padding: 1px 7px;
  border-radius: 3px;
  font-size: 0.7rem;
  color: #fff;
}

.stats-section {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.stat-row {
  display: flex;
  align-items: center;
  gap: 8px;
}

.stat-label {
  font-size: 0.75rem;
  color: var(--c-text-muted);
  min-width: 45px;
}

.stat-track {
  flex: 1;
  height: 12px;
  background: var(--c-surface-light);
  border: 1px solid var(--c-border);
  overflow: hidden;
  position: relative;
}

.stat-fill {
  position: absolute;
  left: 0;
  top: 0;
  bottom: 0;
  transition: width 0.3s ease;
}

.stat-fill.pulse {
  background: linear-gradient(90deg, #f43f5e, #ef4444, #f43f5e);
  background-size: 200% 100%;
  animation: pulse 2s ease-in-out infinite;
}

@keyframes pulse {
  0%, 100% { background-position: 0% 50%; }
  50% { background-position: 100% 50%; }
}

.stat-value {
  font-size: 0.8rem;
  font-weight: bold;
  min-width: 28px;
  text-align: right;
  font-variant-numeric: tabular-nums;
}

.arousal .stat-label {
  color: var(--c-accent);
}

.sex-state-row {
  display: flex;
  gap: 8px;
  margin-top: 10px;
  padding: 6px 8px;
  background: var(--c-surface);
  border: 1px solid var(--c-border);
  border-radius: 6px;
}

.sex-chip {
  display: flex;
  flex-direction: column;
  align-items: center;
  flex: 1;
  gap: 2px;
}

.sex-key {
  font-size: 0.6rem;
  color: var(--c-text-muted);
  text-transform: uppercase;
}

.sex-val {
  font-size: 0.82rem;
  font-weight: 600;
  color: var(--c-accent-light);
}
